package main

import (
	"context"
	"log"

	"github.com/Posedio/gaiax-opa/internal/grpcpb"

	"google.golang.org/grpc"
	"google.golang.org/grpc/credentials/insecure"
	"google.golang.org/grpc/metadata"
	"google.golang.org/protobuf/types/known/structpb"
)

func main() {
	ctx := context.Background()
	conn, err := grpc.NewClient("localhost:50051", grpc.WithTransportCredentials(insecure.NewCredentials()))
	if err != nil {
		log.Fatalf("failed to connect to OPA gRPC server: %v", err)
	}
	defer conn.Close()
	client := grpcpb.NewOPAServiceClient(conn)

	input, _ := structpb.NewStruct(map[string]interface{}{
		"jwt": "eyJhbGciOiJQUzI1NiIsImN0eSI6InZwIiwiZXhwIjoxODA5Njk1MjExNTE0LCJpYXQiOjE3NzgxNTkyMTE1MTQsImlzcyI6ImRpZDp3ZWI6ZGlkLmR1bXNzLm1lIiwia2lkIjoiZGlkOndlYjpkaWQuZHVtc3MubWUjdjItMjAyNiIsInR5cCI6InZwK2p3dCJ9..fgJOZ3Lz5NSdRC8sPVxTRYysEYUv2_cPueeG21fwVHoZc9HK_os1aiQyGFVGn7cl-yl_S7iv7edbheFUd0bIWNnbpPCSvhvvbxJv5b7V-nP8gZLEksPNtYBEUxvYKUVKASUyHsfhOoY4K6khTufiLTi0EtVx4R9ai4uC08fc9gR-AE9U_CumS8325fOeniWmcRcLwNsJqG9OCtW5UBKnXikUr9lky2kprxr4gZ43Sh9AI2dmiHPlJz-KnRyFbhol3J7rMzBOlz_2LL_lVCD_myVeYRcw6g5jLxP5CvFsMMEBVLeHCCDBmSRNirDKPU4Yrg-cDEAsOCbp_ytSkOiHGA",
	})

	// Attach example request metadata. The OPA gRPC plugin lifts these into
	// rego.EvalRequestMetadata so the policy (and custom builtins via
	// BuiltinContext.RequestMetadata) can read them.
	ctx = metadata.AppendToOutgoingContext(ctx,
		"x-id", "demo-1234",
	)

	// Capture response metadata sent back by the policy as gRPC trailers.
	var trailer metadata.MD

	resp, err := client.Query(ctx, &grpcpb.QueryRequest{
		Path: "verify/legalPerson",
		//Path:  "verify/legalPersonData",
		Input: input,
	}, grpc.Trailer(&trailer))
	if err != nil {
		log.Fatalf("Query failed: %v", err)
	}
	log.Printf("decision: %v", resp.GetAllowed())

	if len(trailer) > 0 {
		log.Printf("response metadata (trailer): %v", trailer)
	}

	if resp.GetError() != "" {
		log.Fatalf("policy error: %s", resp.GetError())
	}
	log.Println(resp.GetResult().AsMap())
}
